async def langgraph_stream_events():
    for event in langchain_events:
        yield event


async def test_ai_sdk_stream_adapter_basic_stream():
    adapter = AISDKStreamAdapter()
    ai_sdk_stream = []
    async for sse_event in adapter.stream(langgraph_stream_events()):
        ai_sdk_stream.append(sse_event)

    assert len(ai_sdk_stream) == 14
    assert ai_sdk_stream[0].startswith('data: {"type": "start", "messageId"')
    assert ai_sdk_stream[1].startswith('data: {"type": "text-start"')
    assert ai_sdk_stream[2].startswith('data: {"type": "text-delta"')
    assert ai_sdk_stream[-1] == 'data: [DONE]\n\n'
    assert ai_sdk_stream[-2] == 'data: {"type": "finish"}\n\n'
